const originalItems = $items('Switch', 1);


const fetchedPages = items;


const relationDataMap = {};
for (const page of fetchedPages) {
  if (page.json && page.json.id) {
    const props = page.json.properties;


    const title = props.Stuff?.title[0]?.plain_text || props.Name?.title[0]?.plain_text || 'Невідома назва';


    const entityType = props['Action Tags']?.select?.name || props['Action type']?.select?.name || 'елемент';

    relationDataMap[page.json.id] = {
      title: title,
      entityType: entityType
    };
  }
}


const priorityMap = {
  '⭐⭐⭐⭐⭐': 'важливим і терміновим', '⭐⭐⭐⭐': 'важливим, але не терміновим',
  '⭐⭐⭐': 'терміновим, але не важливим', '⭐⭐': 'не важливим і не терміновим',
  '⭐': 'бажаним до виконання, але не обов\'язковим (хотілка)'
};
const energyMap = {
  '⚡⚡⚡⚡⚡': 'дуже важким і довготривалим', '⚡⚡⚡⚡': 'дуже важким або довготривалим',
  '⚡⚡⚡': 'відносно важким і довготривалим', '⚡⚡': 'відносно важким і відносно довготривалим',
  '⚡': 'швидким і легким'
};
const entityLocale = {
    'Action': 'дія', 'Project': 'проєкт', 'Habit': 'звичка',
    'Reference': 'довідковий матеріал', 'Incubate': 'ідея', 'Inbox': 'елемент', 'Person': 'людина'
};

const finalResults = [];




for (const item of originalItems) {
  const originalItem = item.json;
  const props = originalItem.properties;

  let contentParts = [];


  const entityType = 'Project';
  const title = props.Stuff?.title[0]?.plain_text || '';
  const priorityEmoji = props.Priority?.select?.name || '';
  const energyEmoji = props.Energy?.select?.name || '';
  const contextTags = props.Context?.multi_select.map(tag => tag.name);

  const remainingTasks = props['Remaining Tasks']?.rollup?.number;
  const completionPercent = props['Completion']?.rollup?.number;


  let summary = `Це запис про проєкт з назвою "${title}".`;
  contentParts.push(summary);


  const priorityText = priorityMap[priorityEmoji];
  if (priorityText) {
    contentParts.push(`Цей проєкт є ${priorityText}.`);
  }
  const energyText = energyMap[energyEmoji];
  if (energyText) {
    contentParts.push(`За складністю та часом виконання цей проєкт є ${energyText}.`);
  }

  if (completionPercent !== null && completionPercent !== undefined) {
    contentParts.push(`На даний момент, проєкт завершено на ${Math.round(completionPercent * 100)}%.`);
  }
  if (remainingTasks !== null && remainingTasks !== undefined) {
    contentParts.push(`Залишилось виконати ${remainingTasks} завдань.`);
  }
  if (contextTags && contextTags.length > 0) {
    contentParts.push(`Цей проєкт відноситься до наступних контекстів: ${contextTags.join(', ')}.`);
  }


  function addRelationTitles(prop, narrativePrefix) {
      const relations = prop?.relation || [];
      if (relations.length === 0) return;
      const descriptions = relations.map(r => {
          const relatedItem = relationDataMap[r.id];
          if (!relatedItem) return null;
          const localizedType = entityLocale[relatedItem.entityType] || 'елемент';
          return `${localizedType} «${relatedItem.title}»`;
      }).filter(Boolean);
      if (descriptions.length > 0) {
          contentParts.push(`${narrativePrefix}: ${descriptions.join(', ')}.`);
      }
  }
  addRelationTitles(props['Level up ⬆️'], 'Цей проєкт є частиною');
  addRelationTitles(props['Level down ⬇️'], 'Цей проєкт включає в себе наступні завдання');
  addRelationTitles(props['⚠Depends on'], 'Виконання проєкту залежить від');
  addRelationTitles(props['⛔Blocking'], 'Цей проєкт блокує');
  addRelationTitles(props['Related People'], 'До проєкту залучені');


  const finalContent = contentParts.join(' ');


  const priorityLevel = priorityEmoji.length;
  const energyLevel = energyEmoji.length;
  const finalData = {
      notion_id: originalItem.id,
      entity_type: entityType,
      title: title || null,
      content: finalContent,
      priority_level: priorityLevel,
      energy_level: energyLevel,
      due_date: props['Due Date']?.date?.start || null,
      created_time: props.Created?.created_time || null,
      last_edited_time: props['Last Touch']?.last_edited_time || null,
      metadata: {
          url: originalItem.url,
          done: props.Done?.checkbox || false,
          priority_emoji: priorityEmoji || null,
          energy_emoji: energyEmoji || null,

          remaining_tasks: remainingTasks,
          completion_percent: completionPercent,
          level_up: getRelationDetails(props['Level up ⬆️']), 
          level_down: getRelationDetails(props['Level down ⬇️']),
          related_people: getRelationDetails(props['Related People']),
          context_tags: contextTags || []
      }
  };

  finalResults.push(finalData);
}


function getRelationDetails(prop) {
    const relations = prop?.relation || [];
    return relations.map(r => ({
      id: r.id,
      name: relationDataMap[r.id]?.title || null
    })).filter(r => r.name);
}


return finalResults;

const allRelationIds = new Set(); 

for (const item of items) {
  const props = item.json.properties;


  const addIdsToSet = (prop) => {
    const relations = prop?.relation || [];
    relations.forEach(r => allRelationIds.add(r.id));
