const fetchedPages = items;


const relationDataMap = {};
for (const page of fetchedPages) {
  if (page.json && page.json.id) {
    relationDataMap[page.json.id] = {
      title: page.json.properties.Stuff?.title[0]?.plain_text || 'Невідома назва',
      entityType: page.json.properties['Action Tags']?.select?.name || 'елемент'
    };
  }
}


const priorityMap = { '⭐⭐⭐⭐⭐': 'важливою і терміновою', 
'⭐⭐⭐⭐': 'важливою, але не терміновою', 
'⭐⭐⭐': 'терміновою, але не важливою', 
'⭐⭐': 'не важливою і не терміновою', 
'⭐': 'бажаною до виконання, але не обов\'язковою (хотілка)' };

const energyMap = { 
  '⚡⚡⚡⚡⚡': 'дуже важкою і довготривалою', 
  '⚡⚡⚡⚡': 'дуже важкою або довготривалою', 
  '⚡⚡⚡': 'відносно важкою і довготривалою', 
  '⚡⚡': 'відносно важкою і відносно довготривалою', 
  '⚡': 'швидкою і легкою' };

const entityLocale = { 'Action': 'дія', 'Project': 'проєкт', 'Habit': 'звичка', 'Reference': 'довідковий матеріал', 'Incubate': 'ідея', 'Inbox': 'елемент' };

const finalResults = [];




for (const item of originalItems) {
  const originalItem = item.json;
  const props = originalItem.properties;

  let contentParts = [];

  const entityType = 'Action';
  const title = props.Stuff?.title[0]?.plain_text || '';
  const priorityEmoji = props.Priority?.select?.name || '';
  const energyEmoji = props.Energy?.select?.name || '';
  const contextTags = props.Context?.multi_select.map(tag => tag.name);
  const scheduledDate = props['Scheduled']?.date?.start || null;

  let summary = `Це запис про дію (також класифікується як завдання) з назвою "${title}".`;
  contentParts.push(summary);


  const priorityText = priorityMap[priorityEmoji];
  if (priorityText) { contentParts.push(`Ця дія є ${priorityText}.`); }
  const energyText = energyMap[energyEmoji];
  if (energyText) { contentParts.push(`За складністю та часом виконання ця дія є ${energyText}.`); }
  if (contextTags && contextTags.length > 0) { contentParts.push(`Ця дія відноситься до наступних контекстів: ${contextTags.join(', ')}.`); }


  function addRelationTitles(prop, narrativePrefix) {
      const relations = prop?.relation || [];
      if (relations.length === 0) return;
      const descriptions = relations.map(r => {
          const relatedItem = relationDataMap[r.id];
          if (!relatedItem) return null;
          const localizedType = entityLocale[relatedItem.entityType] || 'елемент';
          return `${localizedType} «${relatedItem.title}»`;
      }).filter(Boolean);
      if (descriptions.length > 0) {
          contentParts.push(`${narrativePrefix}: ${descriptions.join(', ')}.`);
      }
  }
  addRelationTitles(props['Level up ⬆️'], 'Ця дія є частиною');
  addRelationTitles(props['Level down ⬇️'], 'Включає в себе наступні підзадачі');
  addRelationTitles(props['⚠Depends on'], 'Залежить від завершення');
  addRelationTitles(props['⛔Blocking'], 'Блокує виконання');

  const finalContent = contentParts.join(' ');




  const priorityLevel = priorityEmoji.length;
  const energyLevel = energyEmoji.length;


  const getRelationDetails = (prop) => {
    const relations = prop?.relation || [];
    return relations.map(r => ({
      id: r.id,
      name: relationDataMap[r.id]?.title || null
    })).filter(r => r.name); 
  };

  const finalData = {
      notion_id: originalItem.id,
      entity_type: entityType,
      title: title || null,
      content: finalContent,
      priority_level: priorityLevel,
      energy_level: energyLevel,
      due_date: props['Due Date']?.date?.start || null,
      scheduled: scheduledDate,
      created_time: props.Created?.created_time || null,
      last_edited_time: props['Last Touch']?.last_edited_time || null,
      metadata: {
          url: originalItem.url,
          done: props.Done?.checkbox || false,
          priority_emoji: priorityEmoji || null,
          energy_emoji: energyEmoji || null,


          level_up: getRelationDetails(props['Level up ⬆️']),
          level_down: getRelationDetails(props['Level down ⬇️']),
          depends_on: getRelationDetails(props['⚠Depends on']),
          blocking: getRelationDetails(props['⛔Blocking']),

          context_tags: contextTags || []
      }
  };

  finalResults.push(finalData);
}


return finalResults;

